"use client";

import type { ReactNode, FC } from "react";
import { cn } from "@aomi-labs/react";
import { NetworkSelect } from "./network-select";
import { ModelSelect } from "./model-select";
import { AppSelect } from "./app-select";
import { ApiKeyInput } from "./api-key-input";
import { ConnectButton } from "./connect-button";
import { SecretInput } from "./secret-input";

// =============================================================================
// Types
// =============================================================================

export type ControlBarProps = {
  className?: string;
  /** Custom controls to render alongside built-in ones */
  children?: ReactNode;
  /** Hide the model selector */
  hideModel?: boolean;
  /** Hide the App selector */
  hideApp?: boolean;
  /** Hide the API key input */
  hideApiKey?: boolean;
  /** Hide the wallet connect button (default: true) */
  hideWallet?: boolean;
  /** Hide the network selector (default: false) */
  hideNetwork?: boolean;
  /** Hide the secrets input */
  hideSecrets?: boolean;
};

// =============================================================================
// Main Component
// =============================================================================

export const ControlBar: FC<ControlBarProps> = ({
  className,
  children,
  hideModel = false,
  hideApp = false,
  hideApiKey = false,
  hideWallet = true,
  hideNetwork = false,
  hideSecrets = false,
}) => {
  return (
    <div className={cn("flex items-center gap-2", className)}>
      {!hideNetwork && <NetworkSelect />}
      {!hideModel && <ModelSelect />}
      {!hideApp && <AppSelect />}
      {!hideWallet && <ConnectButton />}
      {!hideSecrets && <SecretInput />}
      {children}
      {!hideApiKey && <ApiKeyInput />}
    </div>
  );
};

// =============================================================================
// Re-exports for granular usage
// =============================================================================

export { ModelSelect, type ModelSelectProps } from "./model-select";
export { AppSelect, type AppSelectProps } from "./app-select";
export { ApiKeyInput, type ApiKeyInputProps } from "./api-key-input";
export {
  ConnectButton,
  type ConnectButtonProps,
} from "./connect-button";
export { NetworkSelect, type NetworkSelectProps } from "./network-select";
export { SecretInput, type SecretInputProps } from "./secret-input";

"use client";

import { useEffect, useState, type FC } from "react";
import { ChevronDownIcon, CheckIcon } from "lucide-react";
import { useControl, cn } from "@aomi-labs/react";
import { Button } from "@/components/ui/button";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";

export type ModelSelectProps = {
  className?: string;
  placeholder?: string;
};

export const ModelSelect: FC<ModelSelectProps> = ({
  className,
  placeholder = "Select model",
}) => {
  const {
    state,
    getAvailableModels,
    getCurrentThreadControl,
    onModelSelect,
    isProcessing,
  } = useControl();
  const [open, setOpen] = useState(false);

  // Fetch available models on mount
  useEffect(() => {
    void getAvailableModels();
  }, [getAvailableModels]);

  // Get current thread's selected model (or fall back to default)
  const threadControl = getCurrentThreadControl();
  const selectedModel =
    threadControl.model ?? state.defaultModel ?? state.availableModels[0];

  const models = state.availableModels.length > 0 ? state.availableModels : [];

  // Don't render if no models available
  if (models.length === 0) {
    return (
      <Button
        variant="ghost"
        disabled
        className={cn(
          "h-8 w-auto min-w-[100px] rounded-full px-2 text-xs",
          "text-muted-foreground",
          className,
        )}
      >
        <span className="truncate">Loading...</span>
      </Button>
    );
  }

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <PopoverTrigger asChild>
        <Button
          variant="ghost"
          role="combobox"
          aria-expanded={open}
          disabled={isProcessing}
          className={cn(
            "h-8 w-auto min-w-[100px] justify-between rounded-full px-2 text-xs",
            "text-muted-foreground hover:bg-accent hover:text-accent-foreground",
            isProcessing && "cursor-not-allowed opacity-50",
            className,
          )}
        >
          <span className="truncate">{selectedModel || placeholder}</span>
          <ChevronDownIcon className="ml-2 h-4 w-4 shrink-0 opacity-50" />
        </Button>
      </PopoverTrigger>
      <PopoverContent
        align="center"
        sideOffset={-40}
        className="w-[220px] rounded-3xl p-1 shadow-none"
      >
        <div className="flex flex-col gap-0.5">
          {models.map((model) => (
            <button
              key={model}
              disabled={isProcessing}
              onClick={() => {
                if (isProcessing) return;
                setOpen(false);
                void onModelSelect(model).catch((err) => {
                  console.error("[ModelSelect] onModelSelect failed:", err);
                });
              }}
              className={cn(
                "flex w-full items-center justify-between gap-2 rounded-full px-3 py-2 text-sm outline-none",
                "hover:bg-accent hover:text-accent-foreground",
                "focus:bg-accent focus:text-accent-foreground",
                selectedModel === model && "bg-accent",
                isProcessing && "cursor-not-allowed opacity-50",
              )}
            >
              <span>{model}</span>
              {selectedModel === model && <CheckIcon className="h-4 w-4" />}
            </button>
          ))}
        </div>
      </PopoverContent>
    </Popover>
  );
};

"use client";

import { useState, useEffect, type FC } from "react";
import { ChevronDownIcon, CheckIcon } from "lucide-react";
import { useControl, cn } from "@aomi-labs/react";
import { Button } from "@/components/ui/button";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";

export type AppSelectProps = {
  className?: string;
  placeholder?: string;
};

export const AppSelect: FC<AppSelectProps> = ({
  className,
  placeholder = "Select App",
}) => {
  const {
    state,
    getAuthorizedApps,
    getCurrentThreadApp,
    onAppSelect,
    isProcessing,
  } = useControl();
  const [open, setOpen] = useState(false);

  // Fetch authorized apps on mount
  useEffect(() => {
    void getAuthorizedApps();
  }, [getAuthorizedApps]);

  const selectedApp = getCurrentThreadApp();

  const apps = state.authorizedApps;

  // Show loading state if no apps yet
  if (apps.length === 0) {
    return (
      <Button
        variant="ghost"
        disabled
        className={cn(
          "h-8 w-auto min-w-[100px] rounded-full px-2 text-xs",
          "text-muted-foreground",
          className,
        )}
      >
        <span className="truncate">
          {selectedApp === "khalani" ? "Khalani Swaps" : selectedApp}
        </span>
      </Button>
    );
  }

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <PopoverTrigger asChild>
        <Button
          variant="ghost"
          role="combobox"
          aria-expanded={open}
          disabled={isProcessing}
          className={cn(
            "h-8 w-auto min-w-[100px] justify-between rounded-full px-3 text-xs",
            "text-muted-foreground hover:bg-accent hover:text-accent-foreground",
            isProcessing && "cursor-not-allowed opacity-50",
            className,
          )}
        >
          <span className="truncate">
            {selectedApp
              ? selectedApp === "khalani"
                ? "Khalani Swaps"
                : selectedApp
              : placeholder}
          </span>
          <ChevronDownIcon className="ml-2 h-4 w-4 shrink-0 opacity-50" />
        </Button>
      </PopoverTrigger>
      <PopoverContent
        align="center"
        sideOffset={-40}
        className="w-[180px] rounded-3xl p-1 shadow-none"
      >
        <div className="flex flex-col gap-0.5">
          {apps.map((app: string) => (
            <button
              key={app}
              disabled={isProcessing}
              onClick={() => {
                if (isProcessing) return;
                onAppSelect(app);
                setOpen(false);
              }}
              className={cn(
                "flex w-full items-center justify-between gap-2 rounded-full px-3 py-2 text-sm outline-none",
                "hover:bg-accent hover:text-accent-foreground",
                "focus:bg-accent focus:text-accent-foreground",
                selectedApp === app && "bg-accent",
                isProcessing && "cursor-not-allowed opacity-50",
              )}
            >
              <span>{app === "khalani" ? "Khalani Swaps" : app}</span>
              {selectedApp === app && <CheckIcon className="h-4 w-4" />}
            </button>
          ))}
        </div>
      </PopoverContent>
    </Popover>
  );
};

"use client";

import { useState, type FC } from "react";
import { KeyIcon, CheckIcon, EyeIcon, EyeOffIcon } from "lucide-react";
import { useControl, cn } from "@aomi-labs/react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
  DialogFooter,
} from "@/components/ui/dialog";

export type ApiKeyInputProps = {
  className?: string;
  title?: string;
  description?: string;
};

export const ApiKeyInput: FC<ApiKeyInputProps> = ({
  className,
  title = "Aomi API Key",
  description = "Enter your API key to authenticate with Aomi services.",
}) => {
  const { state, setState } = useControl();
  const [open, setOpen] = useState(false);
  const [inputValue, setInputValue] = useState("");
  const [showKey, setShowKey] = useState(false);

  const hasApiKey = Boolean(state.apiKey);

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <Button
          variant="ghost"
          size="icon"
          className={cn("relative rounded-full", className)}
          aria-label={hasApiKey ? "API key configured" : "Set API key"}
        >
          <KeyIcon className={cn("h-4 w-4", hasApiKey && "text-green-500")} />
        </Button>
      </DialogTrigger>
      <DialogContent className="max-w-[280px] rounded-3xl pl-4">
        <DialogHeader className="border-0">
          <DialogTitle>{title}</DialogTitle>
          <DialogDescription>{description}</DialogDescription>
        </DialogHeader>
        <div className="grid gap-4 py-4">
          <div className="grid gap-2">
            <Label htmlFor="api-key" className="mb-2">
              API Key
            </Label>
            <div className="relative">
              <Input
                id="api-key"
                type={showKey ? "text" : "password"}
                placeholder={hasApiKey ? "********" : "Enter your API key"}
                value={inputValue}
                onChange={(e) => setInputValue(e.target.value)}
                className="rounded-full pr-10"
              />
              <Button
                type="button"
                variant="ghost"
                size="icon"
                className="absolute right-0 top-0 h-full px-3 hover:bg-transparent"
                onClick={() => setShowKey(!showKey)}
                aria-label={showKey ? "Hide API key" : "Show API key"}
              >
                {showKey ? (
                  <EyeIcon className="h-4 w-4" />
                ) : (
                  <EyeOffIcon className="h-4 w-4" />
                )}
              </Button>
            </div>
            {hasApiKey && (
              <p className="text-muted-foreground text-xs">
                <CheckIcon className="mr-1 inline h-3 w-3 text-green-500" />
                API key is configured
              </p>
            )}
          </div>
        </div>
        <DialogFooter>
          {hasApiKey && (
            <Button
              variant="outline"
              className="rounded-full"
              onClick={() => {
                setState({ apiKey: null });
                setInputValue("");
              }}
            >
              Clear
            </Button>
          )}
          <Button
            className="rounded-full"
            onClick={() => {
              if (inputValue.trim()) {
                setState({ apiKey: inputValue.trim() });
                setOpen(false);
                setInputValue("");
              }
            }}
            disabled={!inputValue.trim()}
          >
            Save
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
};

"use client";

import { useEffect, type FC } from "react";
import { cn, getChainInfo, useUser } from "@aomi-labs/react";
import { useAomiAuthAdapter } from "../../lib/aomi-auth-adapter";

export type ConnectButtonProps = {
  className?: string;
  connectLabel?: string;
  onConnectionChange?: (connected: boolean) => void;
};

export const ConnectButton: FC<ConnectButtonProps> = ({
  className,
  connectLabel = "Connect Account",
  onConnectionChange,
}) => {
  const adapter = useAomiAuthAdapter();
  const { setUser } = useUser();
  const identity = adapter.identity;

  useEffect(() => {
    setUser({
      address: identity.address ?? undefined,
      chainId: identity.chainId ?? undefined,
      isConnected: identity.isConnected,
    });
    onConnectionChange?.(identity.isConnected);
  }, [
    identity.address,
    identity.chainId,
    identity.isConnected,
    setUser,
    onConnectionChange,
  ]);

  const handleClick = () => {
    if (identity.isConnected) {
      void adapter.manageAccount();
      return;
    }
    void adapter.connect();
  };

  const ticker = identity.chainId
    ? getChainInfo(identity.chainId)?.ticker
    : undefined;
  const secondaryLabel = identity.isConnected
    ? (identity.secondaryLabel ?? ticker)
    : undefined;
  const primaryLabel = identity.status === "disconnected"
    ? connectLabel
    : identity.primaryLabel;
  const ariaLabel = identity.isConnected ? "Manage account" : "Connect account";

  return (
    <button
      type="button"
      onClick={handleClick}
      className={cn(
        "inline-flex items-center justify-center gap-2 whitespace-nowrap text-sm font-medium",
        "rounded-3xl px-5 py-2.5",
        "bg-primary text-primary-foreground",
        "hover:bg-primary/90",
        "transition-colors",
        "focus-visible:ring-ring focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-offset-2",
        "disabled:pointer-events-none disabled:opacity-50",
        className,
      )}
      aria-label={ariaLabel}
      disabled={!adapter.canManageAccount && !adapter.canConnect}
    >
      <span className="max-w-[180px] truncate">{primaryLabel}</span>
      {identity.isConnected && secondaryLabel && (
        <span className="opacity-50">{secondaryLabel}</span>
      )}
    </button>
  );
};

"use client";

import { useState, type FC } from "react";
import { ChevronDownIcon, CheckIcon } from "lucide-react";
import { cn, SUPPORTED_CHAINS, getChainInfo } from "@aomi-labs/react";
import { Button } from "@/components/ui/button";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import { useAomiAuthAdapter } from "../../lib/aomi-auth-adapter";

export type NetworkSelectProps = {
  className?: string;
  /** Override the default chain list from the lib */
  chains?: typeof SUPPORTED_CHAINS;
};

export const NetworkSelect: FC<NetworkSelectProps> = ({
  className,
  chains = SUPPORTED_CHAINS,
}) => {
  const adapter = useAomiAuthAdapter();
  const { chainId, isConnected } = adapter.identity;
  const switchChain = adapter.switchChain;
  const isPending = adapter.isSwitchingChain;
  const [open, setOpen] = useState(false);

  // Show only when wallet is connected.
  if (!isConnected) return null;

  const currentChain = getChainInfo(chainId);
  const displayName = currentChain?.ticker ?? "Network";

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <PopoverTrigger asChild>
        <Button
          variant="ghost"
          role="combobox"
          aria-expanded={open}
          disabled={isPending || !switchChain}
          className={cn(
            "h-8 w-auto min-w-[80px] justify-between rounded-full px-3 text-xs",
            "text-muted-foreground hover:bg-accent hover:text-accent-foreground",
            (isPending || !switchChain) && "cursor-not-allowed opacity-50",
            className,
          )}
        >
          <span className="truncate">{displayName}</span>
          <ChevronDownIcon className="ml-2 h-4 w-4 shrink-0 opacity-50" />
        </Button>
      </PopoverTrigger>
      <PopoverContent
        align="center"
        sideOffset={-40}
        className="w-[180px] rounded-3xl p-1 shadow-none"
      >
        <div className="flex flex-col gap-0.5">
          {chains.map((chain) => (
            <button
              key={chain.id}
              disabled={isPending || !switchChain}
              onClick={() => {
                if (isPending || chain.id === chainId || !switchChain) return;
                void switchChain(chain.id);
                setOpen(false);
              }}
              className={cn(
                "flex w-full items-center justify-between gap-2 rounded-full px-3 py-2 text-sm outline-none",
                "hover:bg-accent hover:text-accent-foreground",
                "focus:bg-accent focus:text-accent-foreground",
                chainId === chain.id && "bg-accent",
                (isPending || !switchChain) && "cursor-not-allowed opacity-50",
              )}
            >
              <span>{chain.name}</span>
              {chainId === chain.id && <CheckIcon className="h-4 w-4" />}
            </button>
          ))}
        </div>
      </PopoverContent>
    </Popover>
  );
};

"use client";

import { useState, type FC } from "react";
import {
  ShieldIcon,
  CheckIcon,
  EyeIcon,
  EyeOffIcon,
  PlusIcon,
  XIcon,
} from "lucide-react";
import { useControl, cn } from "@aomi-labs/react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
  DialogFooter,
} from "@/components/ui/dialog";

export type SecretInputProps = {
  className?: string;
  title?: string;
  description?: string;
};

type SecretEntry = { name: string; value: string };

export const SecretInput: FC<SecretInputProps> = ({
  className,
  title = "Secrets",
  description = "Add API keys for third-party services. Secrets are stored in memory only and never saved to disk.",
}) => {
  const { ingestSecrets, clearSecrets } = useControl();
  const [open, setOpen] = useState(false);
  const [entries, setEntries] = useState<SecretEntry[]>([
    { name: "", value: "" },
  ]);
  const [savedNames, setSavedNames] = useState<string[]>([]);
  const [showValues, setShowValues] = useState(false);
  const [saving, setSaving] = useState(false);

  const hasSecrets = savedNames.length > 0;

  const updateEntry = (
    index: number,
    field: "name" | "value",
    val: string,
  ) => {
    setEntries((prev) => {
      const next = [...prev];
      next[index] = { ...next[index], [field]: val };
      return next;
    });
  };

  const addEntry = () => {
    setEntries((prev) => [...prev, { name: "", value: "" }]);
  };

  const removeEntry = (index: number) => {
    setEntries((prev) => prev.filter((_, i) => i !== index));
  };

  const validEntries = entries.filter(
    (e) => e.name.trim() && e.value.trim(),
  );

  const handleSave = async () => {
    if (validEntries.length === 0) return;
    setSaving(true);
    try {
      const secrets: Record<string, string> = {};
      for (const entry of validEntries) {
        secrets[entry.name.trim()] = entry.value.trim();
      }
      await ingestSecrets(secrets);
      setSavedNames((prev) => [
        ...new Set([...prev, ...Object.keys(secrets)]),
      ]);
      setEntries([{ name: "", value: "" }]);
      setOpen(false);
    } catch (error) {
      console.error("[SecretInput] Failed to ingest secrets:", error);
    } finally {
      setSaving(false);
    }
  };

  const handleClear = async () => {
    setSaving(true);
    try {
      await clearSecrets();
      setSavedNames([]);
      setEntries([{ name: "", value: "" }]);
    } catch (error) {
      console.error("[SecretInput] Failed to clear secrets:", error);
    } finally {
      setSaving(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <Button
          variant="ghost"
          size="icon"
          className={cn("relative rounded-full", className)}
          aria-label={hasSecrets ? "Secrets configured" : "Add secrets"}
        >
          <ShieldIcon
            className={cn("h-4 w-4", hasSecrets && "text-green-500")}
          />
        </Button>
      </DialogTrigger>
      <DialogContent className="max-w-[340px] rounded-3xl pl-4">
        <DialogHeader className="border-0">
          <DialogTitle>{title}</DialogTitle>
          <DialogDescription>{description}</DialogDescription>
        </DialogHeader>
        <div className="grid gap-3 py-4">
          {hasSecrets && (
            <div className="text-muted-foreground text-xs">
              <CheckIcon className="mr-1 inline h-3 w-3 text-green-500" />
              {savedNames.length} secret{savedNames.length > 1 ? "s" : ""}{" "}
              configured: {savedNames.join(", ")}
            </div>
          )}

          {entries.map((entry, index) => (
            <div key={index} className="flex items-end gap-2">
              <div className="grid flex-1 gap-1">
                {index === 0 && (
                  <Label className="text-xs">Name</Label>
                )}
                <Input
                  type="text"
                  placeholder="MY_API_KEY"
                  value={entry.name}
                  onChange={(e) => updateEntry(index, "name", e.target.value)}
                  className="h-8 rounded-full text-xs"
                />
              </div>
              <div className="grid flex-1 gap-1">
                {index === 0 && (
                  <Label className="flex items-center gap-1 text-xs">
                    Value
                    <Button
                      type="button"
                      variant="ghost"
                      size="icon"
                      className="h-4 w-4 p-0 hover:bg-transparent"
                      onClick={() => setShowValues(!showValues)}
                      aria-label={showValues ? "Hide values" : "Show values"}
                    >
                      {showValues ? (
                        <EyeIcon className="h-3 w-3" />
                      ) : (
                        <EyeOffIcon className="h-3 w-3" />
                      )}
                    </Button>
                  </Label>
                )}
                <Input
                  type={showValues ? "text" : "password"}
                  placeholder="sk-..."
                  value={entry.value}
                  onChange={(e) => updateEntry(index, "value", e.target.value)}
                  className="h-8 rounded-full text-xs"
                />
              </div>
              {entries.length > 1 && (
                <Button
                  type="button"
                  variant="ghost"
                  size="icon"
                  className="h-8 w-8 shrink-0 rounded-full"
                  onClick={() => removeEntry(index)}
                  aria-label="Remove entry"
                >
                  <XIcon className="h-3 w-3" />
                </Button>
              )}
            </div>
          ))}

          <Button
            type="button"
            variant="ghost"
            size="sm"
            className="w-fit rounded-full text-xs"
            onClick={addEntry}
          >
            <PlusIcon className="mr-1 h-3 w-3" />
            Add another
          </Button>
        </div>
        <DialogFooter>
          {hasSecrets && (
            <Button
              variant="outline"
              className="rounded-full"
              onClick={() => void handleClear()}
              disabled={saving}
            >
              Clear all
            </Button>
          )}
          <Button
            className="rounded-full"
            onClick={() => void handleSave()}
            disabled={validEntries.length === 0 || saving}
          >
            Save
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
};

"use client";

import { useMemo } from "react";
import {
  useAccount as useParaAccount,
  useModal,
} from "@getpara/react-sdk";
import type { Chain } from "viem";
import {
  useAccount as useWagmiAccount,
  useConfig,
  useSendTransaction,
  useSignTypedData,
  useSwitchChain,
} from "wagmi";
import type {
  WalletEip712Payload,
  WalletTxPayload,
} from "@aomi-labs/react";
import {
  DISABLED_PROVIDER_STATE,
  executeWalletCalls,
  toAAWalletCall,
} from "@aomi-labs/react";
import {
  AOMI_AUTH_BOOTING_IDENTITY,
  AOMI_AUTH_DISCONNECTED_IDENTITY,
  formatAddress,
  formatAuthProvider,
  inferAuthProvider,
  type AomiAuthIdentity,
} from "./auth-identity";

type ParaAccountShape = {
  isLoading: boolean;
  isConnected: boolean;
  embedded: {
    email?: string;
    farcasterUsername?: string;
    telegramUserId?: string;
    authMethods?: Set<unknown>;
    wallets?: Array<{ address?: string }>;
  };
  external: {
    evm?: {
      address?: string;
      chainId?: number | string;
    };
  };
};

type WagmiAccountShape = {
  address?: `0x${string}`;
  chainId?: number;
  isConnected: boolean;
};

type WagmiConfigShape = {
  chains: readonly Chain[];
};

function getPreferredRpcUrl(chain: Chain): string {
  return chain.rpcUrls.default.http[0]
    ?? chain.rpcUrls.public?.http[0]
    ?? "";
}

export type AomiAuthAdapter = {
  identity: AomiAuthIdentity;
  isReady: boolean;
  isSwitchingChain: boolean;
  canConnect: boolean;
  canManageAccount: boolean;
  connect: () => Promise<void>;
  manageAccount: () => Promise<void>;
  switchChain?: (chainId: number) => Promise<void>;
  sendTransaction?: (
    payload: WalletTxPayload,
  ) => Promise<{ txHash: string; amount?: string }>;
  signTypedData?: (
    payload: WalletEip712Payload,
  ) => Promise<{ signature: string }>;
};

const DISCONNECTED_PARA_ACCOUNT: ParaAccountShape = {
  isLoading: false,
  isConnected: false,
  embedded: {},
  external: {},
};

const DISCONNECTED_WAGMI_ACCOUNT: WagmiAccountShape = {
  address: undefined,
  chainId: undefined,
  isConnected: false,
};

const DISCONNECTED_WAGMI_CONFIG: WagmiConfigShape = {
  chains: [],
};

function useSafeParaAccount(): ParaAccountShape {
  try {
    return useParaAccount() as ParaAccountShape;
  } catch {
    return DISCONNECTED_PARA_ACCOUNT;
  }
}

function useSafeParaModal(): { openModal: (args?: { step?: string }) => void } | null {
  try {
    return useModal() as { openModal: (args?: { step?: string }) => void };
  } catch {
    return null;
  }
}

function useSafeWagmiAccount(): WagmiAccountShape {
  try {
    return useWagmiAccount() as WagmiAccountShape;
  } catch {
    return DISCONNECTED_WAGMI_ACCOUNT;
  }
}

function useSafeWagmiConfig(): WagmiConfigShape {
  try {
    const config = useConfig();
    return {
      chains: config.chains ?? [],
    };
  } catch {
    return DISCONNECTED_WAGMI_CONFIG;
  }
}

function useSafeSwitchChain(): {
  switchChain?: (args: { chainId: number }) => void;
  switchChainAsync?: (args: { chainId: number }) => Promise<unknown>;
  isPending: boolean;
} {
  try {
    const result = useSwitchChain();
    return {
      switchChain: result.switchChain,
      switchChainAsync: result.switchChainAsync,
      isPending: result.isPending,
    };
  } catch {
    return {
      switchChain: undefined,
      switchChainAsync: undefined,
      isPending: false,
    };
  }
}

function useSafeSendTransaction(): {
  sendTransactionAsync?: (args: {
    chainId?: number;
    to: `0x${string}`;
    value?: bigint;
    data?: `0x${string}`;
  }) => Promise<string>;
} {
  try {
    return useSendTransaction() as {
      sendTransactionAsync?: (args: {
        chainId?: number;
        to: `0x${string}`;
        value?: bigint;
        data?: `0x${string}`;
      }) => Promise<string>;
    };
  } catch {
    return { sendTransactionAsync: undefined };
  }
}

function useSafeSignTypedData(): {
  signTypedDataAsync?: (args: unknown) => Promise<string>;
} {
  try {
    return useSignTypedData() as {
      signTypedDataAsync?: (args: unknown) => Promise<string>;
    };
  } catch {
    return { signTypedDataAsync: undefined };
  }
}

export function useAomiAuthAdapter(): AomiAuthAdapter {
  const paraAccount = useSafeParaAccount();
  const paraModal = useSafeParaModal();
  const {
    address: wagmiAddress,
    chainId,
    isConnected: wagmiConnected,
  } = useSafeWagmiAccount();
  const { switchChainAsync, isPending } = useSafeSwitchChain();
  const { sendTransactionAsync } = useSafeSendTransaction();
  const { signTypedDataAsync } = useSafeSignTypedData();
  const wagmiConfig = useSafeWagmiConfig();

  const chainsById = useMemo<Record<number, Chain>>(
    () =>
      Object.fromEntries(
        (wagmiConfig.chains ?? []).map((chain) => [chain.id, chain]),
      ),
    [wagmiConfig.chains],
  );

  return useMemo(() => {
    const isConnected = Boolean(paraAccount.isConnected || wagmiConnected);
    const isBooting = paraAccount.isLoading && !isConnected;

    const embeddedPrimary =
      paraAccount.embedded.email
      ?? paraAccount.embedded.farcasterUsername
      ?? paraAccount.embedded.telegramUserId
      ?? undefined;
    const embeddedWallet = paraAccount.embedded.wallets?.[0] as
      | { address?: string }
      | undefined;
    const embeddedAddress = embeddedWallet?.address;
    const externalAddress = paraAccount.external.evm?.address;
    const address = wagmiAddress ?? externalAddress ?? embeddedAddress ?? undefined;
    const authProvider = inferAuthProvider(paraAccount.embedded.authMethods);
    const providerLabel = formatAuthProvider(authProvider);

    const identity: AomiAuthIdentity = isBooting
      ? {
          ...AOMI_AUTH_BOOTING_IDENTITY,
          chainId: chainId ?? undefined,
        }
      : isConnected && embeddedPrimary
        ? {
            status: "connected",
            isConnected: true,
            address,
            chainId: chainId ?? undefined,
            authProvider,
            primaryLabel: embeddedPrimary,
            secondaryLabel: providerLabel,
          }
        : isConnected && address
          ? {
              status: "connected",
              isConnected: true,
              address,
              chainId: chainId ?? undefined,
              authProvider,
              primaryLabel: formatAddress(address) ?? "Connected wallet",
              secondaryLabel: undefined,
            }
          : {
              ...AOMI_AUTH_DISCONNECTED_IDENTITY,
              chainId: chainId ?? undefined,
              authProvider,
            };

    return {
      identity,
      isReady: !isBooting,
      isSwitchingChain: isPending,
      canConnect: Boolean(paraModal) && !identity.isConnected,
      canManageAccount: Boolean(paraModal) && identity.isConnected,
      connect: async () => {
        paraModal?.openModal({ step: "AUTH_MAIN" });
      },
      manageAccount: async () => {
        paraModal?.openModal({ step: "ACCOUNT_MAIN" });
      },
      switchChain: switchChainAsync
        ? async (nextChainId: number) => {
            await switchChainAsync({ chainId: nextChainId });
          }
        : undefined,
      sendTransaction: sendTransactionAsync
        ? async (payload: WalletTxPayload) => {
            if (!payload.to) {
              throw new Error("pending_transaction_missing_call_data");
            }

            const call = toAAWalletCall(payload, payload.chainId ?? chainId ?? 1);
            const execution = await executeWalletCalls({
              callList: [call],
              currentChainId: chainId ?? call.chainId,
              capabilities: undefined,
              localPrivateKey: null,
              providerState: DISABLED_PROVIDER_STATE,
              sendCallsSyncAsync: async () => {
                throw new Error("wallet_send_calls_not_supported");
              },
              sendTransactionAsync: async ({
                chainId: txChainId,
                to,
                value,
                data,
              }) => {
                return sendTransactionAsync({
                  chainId: txChainId,
                  to,
                  value,
                  data,
                });
              },
              switchChainAsync: switchChainAsync
                ? async ({ chainId: nextChainId }) => {
                    await switchChainAsync({ chainId: nextChainId });
                  }
                : async () => {
                    throw new Error("wallet_switch_chain_not_supported");
                  },
              chainsById,
              getPreferredRpcUrl,
            });

            return {
              txHash: execution.txHash,
              amount: payload.value,
            };
          }
        : undefined,
      signTypedData: signTypedDataAsync
        ? async (payload: WalletEip712Payload) => {
            const signature = await signTypedDataAsync(payload as never);
            return { signature };
          }
        : undefined,
    };
  }, [
    chainId,
    isPending,
    paraAccount.embedded,
    paraAccount.external,
    paraAccount.isConnected,
    paraAccount.isLoading,
    paraModal,
    chainsById,
    sendTransactionAsync,
    signTypedDataAsync,
    switchChainAsync,
    wagmiAddress,
    wagmiConnected,
  ]);
}

"use client";

export type AomiAuthStatus = "booting" | "disconnected" | "connected";

export type AomiAuthIdentity = {
  status: AomiAuthStatus;
  isConnected: boolean;
  address?: string;
  chainId?: number;
  authProvider?: string;
  primaryLabel: string;
  secondaryLabel?: string;
};

export const AOMI_AUTH_DISCONNECTED_IDENTITY: AomiAuthIdentity = {
  status: "disconnected",
  isConnected: false,
  address: undefined,
  chainId: undefined,
  authProvider: undefined,
  primaryLabel: "Not connected",
  secondaryLabel: undefined,
};

export const AOMI_AUTH_BOOTING_IDENTITY: AomiAuthIdentity = {
  status: "booting",
  isConnected: false,
  address: undefined,
  chainId: undefined,
  authProvider: undefined,
  primaryLabel: "Loading Wallet...",
  secondaryLabel: undefined,
};

export function formatAddress(address?: string): string | undefined {
  if (!address) return undefined;
  return `${address.slice(0, 5)}..${address.slice(-2)}`;
}

export function formatAuthProvider(provider?: string): string | undefined {
  if (!provider) return undefined;

  const labelMap: Record<string, string> = {
    google: "Google",
    github: "GitHub",
    apple: "Apple",
    facebook: "Facebook",
    x: "X",
    discord: "Discord",
    farcaster: "Farcaster",
    telegram: "Telegram",
    email: "Email",
    phone: "Phone",
    wallet: "Wallet",
  };

  return labelMap[provider] ?? provider;
}

export function inferAuthProvider(authMethods: unknown): string | undefined {
  if (!(authMethods instanceof Set) || authMethods.size === 0) return undefined;

  const allowed = new Set([
    "google",
    "github",
    "apple",
    "facebook",
    "x",
    "discord",
    "farcaster",
    "telegram",
    "email",
    "phone",
  ]);

  for (const method of authMethods) {
    if (typeof method !== "string") continue;
    const normalized = method.toLowerCase();
    if (allowed.has(normalized)) return normalized;
  }

  const first = authMethods.values().next().value;
  return typeof first === "string" ? first.toLowerCase() : undefined;
}
